/**
 * Effort Level Detector — Reads the current /effort setting
 * CC 2.1.76+: /effort slash command sets model effort level mid-session.
 *
 * Detection order:
 * 1. hook input field (effort_level)
 * 2. CLAUDE_EFFORT environment variable
 * 3. Default: 'medium'
 */

import type { HookInput } from '../types.js';

export type EffortLevel = 'low' | 'medium' | 'high';

const VALID_LEVELS = new Set<EffortLevel>(['low', 'medium', 'high']);

/**
 * Detect current effort level from hook input or environment.
 */
export function detectEffortLevel(input: HookInput): EffortLevel {
  // 1. Hook input (CC may inject this field)
  const fromInput = (input as unknown as Record<string, unknown>).effort_level;
  if (typeof fromInput === 'string' && VALID_LEVELS.has(fromInput as EffortLevel)) {
    return fromInput as EffortLevel;
  }

  // 2. Environment variable
  const fromEnv = process.env.CLAUDE_EFFORT;
  if (fromEnv && VALID_LEVELS.has(fromEnv as EffortLevel)) {
    return fromEnv as EffortLevel;
  }

  // 3. Default
  return 'medium';
}

/**
 * Token budget multipliers per effort level.
 * Low: minimal context injection. High: full context.
 */
export function effortTokenBudget(level: EffortLevel, baseBudget: number): number {
  switch (level) {
    case 'low':  return Math.round(baseBudget * 0.25);  // 200t from 800t base
    case 'high': return Math.round(baseBudget * 1.5);   // 1200t from 800t base
    default:     return baseBudget;                      // 800t
  }
}
